   integer file_handle;

   typedef struct packed {
      logic [10:0] a;
      logic [2:0]  b;
   } test_struct_t;

   test_struct_t test;

   initial begin
      integer scan;
      file_handle = $fopen("test.txt", "r");
      scan = $fscanf(file_handle,
                     "%h %h",
                     test.a,
                     test.b);
      $finish;
   end

endmodule
